// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	if (isLoading || newValue === '') {
		g_form.setValue('name', g_form.getValue('tasker_process') + ' - ' + g_form.getValue('repeat_description'));

		return;
	}
	// STRY0049316 FIX and STRY0058499 - if the start date is chnaged, ensure the new date is in the future.
	g_scratchpad.savedScheduleStartDate = oldValue;
	checkStartDateInFuture(newValue);
	// now check to see if the start date was cleared
	if (g_form.getValue("start_date") == g_scratchpad.savedScheduleStartDate) {
		return false;
	}

	setRepeatText();
	setDayOfWeek();
}

// NOTE: RAJ - this should go into a script that loads for all screens one time.
// any changes made here should also be made in all onChange events and all onLoad events for the Tasker Scheduler form
// 2 functions, setRepeatText() and setRepeatTextResponse(response) have been added to each script
function setRepeatText() {
	var repeatCount = g_form.getValue("repeat_count");
	var startDate = g_form.getValue("start_date");

	if (!startDate) {
		startDate = "";
	}
	if (!repeatCount) {
		repeatCount = 0;
	}

	var ga = new GlideAjax("TaskerSchedulerScript");
	ga.addParam('sysparm_name', 'scheduleTime');
	ga.addParam('sysparm_repeat_type', g_form.getValue("repeat_type"));
	ga.addParam('sysparm_repeat_count', repeatCount);
	ga.addParam('sysparm_start_date', startDate);
	ga.addParam('sysparm_days_of_week', g_form.getValue("days_of_week"));
	ga.addParam('sysparm_monthly_type', g_form.getValue("monthly_type"));
	ga.addParam('sysparm_yearly_type', g_form.getValue("yearly_type"));
	ga.getXML(setRepeatTextResponse, null);
}

function setRepeatTextResponse(response) {
	var answer = response.responseXML.documentElement.getAttribute("answer");
	g_form.setValue("repeat_description",answer);
}

function setDayOfWeek() {
	var repeatType = g_form.getValue("repeat_type");
	var startDate = g_form.getValue("start_date");
	if (repeatType == 'weekly' ){


		var ga = new GlideAjax("TaskerSchedulerScript");
		ga.addParam('sysparm_name', 'getDayOfWeek');
		ga.addParam('sysparm_start_date', startDate);
		ga.getXML(setRepatOnField, null);
	}
}

function setRepatOnField(response) {
	var answer = response.responseXML.documentElement.getAttribute("answer");
	g_form.setValue("days_of_week",answer);
}

function checkStartDateInFuture(newStartDate) {
	var ajax = new GlideAjax('MyDateTimeAjax');
	ajax.addParam('sysparm_name', 'nowDateTime');
	ajax.addParam('sysparm_field', newStartDate);

	ajax.getXML(function (){
		var data = ajax.getAnswer();
		var newDate = (JSON.parse(data));

		var current_dateTime = newDate.now;
		var startDate = newDate.valueToCompare;
		//we only want to compare the date, not the time
		//the reason is that if we use hours, minutes and seconds, if we initialize the now object with the time five seconds ago
		// it will the current time would be a date in the future because it is five seconds greater than the previous date

		var current_dateTimeStr = current_dateTime.toString().substring(0, 10);
		var startDateStr = startDate.toString().substring(0, 10);
		if(current_dateTimeStr > startDateStr){
			g_form.showErrorBox('start_date','The Start Date must be Today or a Future Date.',true);
			g_form.setValue('start_date', g_scratchpad.savedScheduleStartDate);
		}
	});
}
